import { StateGraph, START, END } from "@langchain/langgraph";
import { StateAnnotation, ProfileGraphState } from "./state";
import { persisterNode } from "./nodes/persister";
import { ingestionSubGraph } from "./subgraphs/ingestion";
import { interviewerSubGraph } from "./subgraphs/interviewer";
import { improverSubGraph } from "./subgraphs/improver";

async function supervisorNode(state: typeof StateAnnotation.State) {
  // Check if we have db writes pending from a previous cycle that Supervisor happened to intercept (unlikely due to routing, but safe)
  if (state.pendingDbWrites && state.pendingDbWrites.length > 0) {
    return {};
  }

  // Logic based Routing (can also use LLM for complex routing)
  if (!state.currentPhase) {
    return { currentPhase: "Initialize", nextAgent: "IngestionAgent" };
  }

  if (state.githubHandle && (!state.repositories || state.repositories.length === 0)) {
    return { nextAgent: "IngestionAgent" };
  }

  // Master CV Improvements
  if (state.currentPhase === "Improver") {
    return { nextAgent: "ImproverAgent" };
  }

  // Interview flow
  if (
    state.missingCount !== 0 ||
    (state.interviewHistory &&
      state.interviewHistory.length > 0 &&
      !state.interviewHistory[state.interviewHistory.length - 1]?.answer)
  ) {
    return { nextAgent: "InterviewerAgent" };
  }

  return { nextAgent: "END" };
}

function supervisorRouter(state: typeof StateAnnotation.State) {
  if (state.pendingDbWrites && state.pendingDbWrites.length > 0) {
    return "Persister";
  }
  if (state.nextAgent === "IngestionAgent") return "IngestionAgent";
  if (state.nextAgent === "InterviewerAgent") return "InterviewerAgent";
  if (state.nextAgent === "ImproverAgent") return "ImproverAgent";
  return END;
}

function subGraphRouter(state: typeof StateAnnotation.State) {
  // If a subgraph generated db writes, route to Persister before returning to Supervisor
  if (state.pendingDbWrites && state.pendingDbWrites.length > 0) {
    return "Persister";
  }
  return "Supervisor";
}

function persisterRouter(state: typeof StateAnnotation.State) {
  // After persisting, always return to Supervisor to re-evaluate state
  return "Supervisor";
}

const workflow = new StateGraph(StateAnnotation)
  .addNode("Supervisor", supervisorNode)
  .addNode("IngestionAgent", ingestionSubGraph)
  .addNode("InterviewerAgent", interviewerSubGraph)
  .addNode("ImproverAgent", improverSubGraph)
  .addNode("Persister", persisterNode)

  .addEdge(START, "Supervisor")
  .addConditionalEdges("Supervisor", supervisorRouter, {
    Persister: "Persister",
    IngestionAgent: "IngestionAgent",
    InterviewerAgent: "InterviewerAgent",
    [END]: END,
  })
  .addConditionalEdges("IngestionAgent", subGraphRouter, {
    Persister: "Persister",
    Supervisor: "Supervisor",
  })
  .addConditionalEdges("InterviewerAgent", subGraphRouter, {
    Persister: "Persister",
    Supervisor: "Supervisor",
  })
  .addConditionalEdges("ImproverAgent", subGraphRouter, {
    Persister: "Persister",
    Supervisor: "Supervisor",
  })
  .addConditionalEdges("Persister", persisterRouter, {
    Supervisor: "Supervisor",
  });

export const appGraph = workflow.compile();

import { ProfileGraphState } from "../state";
import { pool } from "../../db/client";
import { RunnableConfig } from "@langchain/core/runnables";
import { dispatchCustomEvent } from "@langchain/core/callbacks/dispatch";

export async function persisterNode(state: ProfileGraphState, config?: RunnableConfig) {
  if (!state.pendingDbWrites || state.pendingDbWrites.length === 0) {
    return {};
  }

  await dispatchCustomEvent(
    "progress",
    { msg: `[Persister] Writing ${state.pendingDbWrites.length} transaction(s) to Database...` },
    config
  );

  let newUserProfileId = state.userProfileId;

  for (const directive of state.pendingDbWrites) {
    try {
      if (directive.action === "insert") {
        if (directive.targetTable === "projects_raw_text") {
          await pool.query(
            "INSERT INTO projects_raw_text (user_profile_id, repo_name, raw_text) VALUES ($1, $2, $3) ON CONFLICT DO NOTHING",
            [newUserProfileId, directive.data.repo_name, directive.data.raw_text]
          );
        } else if (directive.targetTable === "project_embeddings") {
          await pool.query(
            "INSERT INTO project_embeddings (project_id, chunk_index, chunk_text, embedding) VALUES ($1, $2, $3, $4)",
            [
              directive.data.project_id,
              directive.data.chunk_index,
              directive.data.chunk_text,
              directive.data.embedding,
            ]
          );
        } else if (directive.targetTable === "user_profiles" && newUserProfileId === null) {
          const res = await pool.query(
            "INSERT INTO user_profiles (github_handle, base_cv) VALUES ($1, $2) RETURNING id",
            [directive.data.github_handle, directive.data.base_cv]
          );
          newUserProfileId = res.rows[0].id;
        }
      } else if (directive.action === "update") {
        if (directive.targetTable === "user_profiles" && newUserProfileId !== null) {
          if (directive.data.demographics_json) {
            await pool.query("UPDATE user_profiles SET demographics_json = $1 WHERE id = $2", [
              directive.data.demographics_json,
              newUserProfileId,
            ]);
          }
          if (directive.data.base_cv) {
            await pool.query("UPDATE user_profiles SET base_cv = $1 WHERE id = $2", [
              directive.data.base_cv,
              newUserProfileId,
            ]);
          }
          if (directive.data.extended_cv) {
            await pool.query("UPDATE user_profiles SET extended_cv = $1 WHERE id = $2", [
              directive.data.extended_cv,
              newUserProfileId,
            ]);
          }
        }
      }
    } catch (e: any) {
      console.error(`[Persister] Failed DB mapping for ${directive.targetTable}: ${e.message}`);
    }
  }

  // Clear the DB writes so they don't trigger again, and potentially update the userProfileId
  return {
    pendingDbWrites: [], // Note: Empty array to trigger reset via reducer logic
    userProfileId: newUserProfileId,
  };
}

export function buildOntologyPrompt({
  cvText,
  repoContext,
}: {
  cvText: string;
  repoContext: string;
}) {
  return `You are a strict data structurer converting a candidate's history into a linked Relational Graph.
Read their Base CV and ingested Repositories and map out their foundational graph.

CRITICAL RULES:
1. Every new entity must have a unique "id" (e.g. s1, e1, ed1).
2. FOR PROJECTS, the "id" MUST exactly be the Repository Name provided in the Repos context (e.g. "daicer-ui"). DO NOT invent fake ids like "p1".
3. ALL relational mappings MUST use these strict IDs (e.g., linked_project_ids, linked_skill_ids). DO NOT use string matching or names for relations.

Base CV: ${cvText}
Repos: ${repoContext}`;
}

export function analyzeSkillsPrompt({
  cvText,
  repoContext,
  ontology,
  history,
}: {
  cvText: string;
  repoContext: string;
  ontology: any;
  history: string;
}) {
  return `You are collaboratively helping a candidate complete their Skills profile based on their Ontological Knowledge Graph.
Base CV: ${cvText}
Repos: ${repoContext}

CURRENT KNOWLEDGE GRAPH:
${JSON.stringify(ontology, null, 2)}

Prior Conversation History:
${history}

Your goal: Help gather more details to build a complete resume. DO NOT interrogate the user, force them to prove their skills, or ask why something is missing from their CV. If a skill isn't tied to a project, politely ask them to share a bit more about how they used it. We just want to add more rich detail.
Do not inquire too much. If they have already answered a question or if the graph has decent detail, output an empty array for knowledgeGaps.`;
}

export function analyzeEducationPrompt({
