  ontology: any;
  history: string;
}) {
  return `You are collaboratively helping a candidate complete their Education details based on their Knowledge Graph.
Base CV: ${cvText}

CURRENT KNOWLEDGE GRAPH:
${JSON.stringify(ontology, null, 2)}

Prior Conversation History:
${history}

Your goal: Help gather more details about their educational background. DO NOT interrogate the candidate or point out missing information as a flaw. Instead, politely ask them to share how their academic background contributed to their current skills, just to add more detail to the resume.
Do not inquire too much. If they have already answered a question or if the graph has decent detail, output an empty array for knowledgeGaps.`;
}

export function analyzeExperiencePrompt({
  cvText,
  repoContext,
  ontology,
  history,
}: {
  cvText: string;
  repoContext: string;
  ontology: any;
  history: string;
}) {
  return `You are collaboratively helping a candidate complete their Work Experience and Projects timeline based on their Knowledge Graph.
Base CV: ${cvText}
Repos: ${repoContext}

CURRENT KNOWLEDGE GRAPH:
${JSON.stringify(ontology, null, 2)}

Prior Conversation History:
${history}

Your goal: Help gather more context about their work history. DO NOT interrogate them or challenge them to prove anything. If a repository isn't linked to a role, lightly and politely ask them if they built it for a specific job or as a side project, so you can map it properly on their completed resume.
Do not inquire too much. If they have already answered a question, or if there's sufficient detail, output an empty array for knowledgeGaps.`;
}

export function compileExtendedCVPrompt({
  cvText,
  repoContext,
  demographics,
}: {
  cvText: string;
  repoContext: string;
  demographics: any;
}) {
  return `You are an elite Staff-Level Engineer and Master CV Architect.
Your task is to compile a "Master Extended CV". This is an absolutely enormous, comprehensive Markdown document that natively embodies every single piece of extracted knowledge we have about this candidate.

Base CV:
${cvText}

Extensive Demographics & Historical Interview Q&A Arrays:
${JSON.stringify(demographics, null, 2)}

Full Context Nodes from Github Repos:
${repoContext}

INSTRUCTIONS:
1. Natively interleave the Base CV with context you discover in the Repositories and Q&A history.
2. If a timeline or job was mentioned in the Q&A, you MUST tie the repo architectures to those jobs explicitly.
3. This is not constrained to standard 1-page CV rules. It is an "Extended Context CV". Expand on everything.
Output ONLY the raw markdown of the final compiled document.`;
}

export const INTERVIEWER_PROMPTS = {
  completenessSystem: `You are an elite Staff-Level Technical Profiler.
Review the provided candidate Base CV and any repository context available.
Identify if the profile is sufficiently detailed in these structural areas: 'technical skills', 'education detail', 'work timelines'.

CRITICAL INSTRUCTION: You MUST strictly enforce that the user has explicitly declared:
1. "Target Position" (What exact job titles or roles are they looking for?)
2. "Favorite Technologies" (What specific frameworks or languages do they love the most?)

If EITHER of these two are missing or vague, you MUST add them to the missing areas array.
If the candidate's CV is extremely sparse (e.g. just lists a job with no detail), flag the area as missing.
If they have a decently populated CV (even if basic) and BOTH target position and favorite tech are clear, leave the missing areas array empty.`,
  interviewerSystem: `You are collaboratively helping a candidate complete their profile.
Review their history, their CV, and the specific missing area flagged.
Draft a polite, concise, single question to ask the candidate to elaborate on this missing area.
DO NOT interrogate them. Keep it conversational.
If the missing area is 'Target Position' or 'Favorite Technologies', ask them directly about it!`,
  cvImproverSystem: `You are an elite Resume Architect.
Using the candidate's existing Master CV, and their recent Q&A interaction, output a newly improved markdown Master CV that natively weaves in the information they just shared.
Do not output anything except the pure markdown of the updated CV.`,
};

import { BaseMessage } from "@langchain/core/messages";
import { Annotation } from "@langchain/langgraph";

// Action payloads for the Persister node to execute
export interface DbDirective {
  targetTable: "user_profiles" | "cv_versions" | "projects_raw_text" | "project_embeddings";
  action: "insert" | "update" | "upsert";
  data: any;
  whereClause?: any; // e.g. { id: 1 }
}

export interface ProfileGraphState {
  githubUrl: string;
  baseCv: string;
  githubHandle: string;
  userProfileId: number | null;
  workingExtendedCv: string;
  critiqueFeedback: string[];

  // Repositories & Processing Tracking
  repositories: any[];
  ingestedProjects: number;

  // Sub-Agent and Orchestration State
  nextAgent: string | null;
  pendingDbWrites: DbDirective[];

  // Interview tracking
  knowledgeGaps: string[];
  messages: BaseMessage[];
  finalSQLDemographics: string;
  missingCount: number;
  missingInfoList: string[];
  interviewHistory: { question: string; answer: string }[];

  // General UI Display
  currentPhase: string;
  wizardCompleted: boolean;
}

export const StateAnnotation = Annotation.Root({
  githubUrl: Annotation<string>({
    reducer: (a, b) => (b !== undefined ? b : a),
    default: () => "",
  }),
  baseCv: Annotation<string>({
    reducer: (a, b) => (b !== undefined ? b : a),
    default: () => "",
  }),
  githubHandle: Annotation<string>({
    reducer: (a, b) => (b !== undefined ? b : a),
    default: () => "",
  }),
  userProfileId: Annotation<number | null>({
    reducer: (a, b) => (b !== null ? b : a),
    default: () => null,
  }),
  workingExtendedCv: Annotation<string>({
    reducer: (a, b) => (b !== undefined ? b : a),
    default: () => "",
  }),
  critiqueFeedback: Annotation<string[]>({
    reducer: (a, b) => b || a, // Will overwrite on each critique cycle
    default: () => [],
  }),
  repositories: Annotation<any[]>({
    reducer: (a, b) => b || a, // Reset or overwrite

    default: () => [],
  }),
  ingestedProjects: Annotation<number>({
    reducer: (a, b) => a + (b || 0),
    default: () => 0,
  }),

  // --- New Sub-Agent Orchestration State ---
  nextAgent: Annotation<string | null>({
    reducer: (a, b) => (b !== undefined ? b : a),
    default: () => null,
  }),
  pendingDbWrites: Annotation<DbDirective[]>({
    reducer: (state, update) => {
      if (update && update.length === 0) return [];
      return state.concat(update || []);
    },
    default: () => [],
  }),

  knowledgeGaps: Annotation<string[]>({
    reducer: (a, b) => b || a, // Simple override
    default: () => [],
  }),
  messages: Annotation<BaseMessage[]>({
    reducer: (a, b) => a.concat(b || []),
    default: () => [],
  }),
  finalSQLDemographics: Annotation<string>({
    reducer: (a, b) => b || a,
    default: () => "",
  }),
  missingCount: Annotation<number>({
    reducer: (a, b) => (b !== undefined ? b : a),
    default: () => 0,
  }),
  missingInfoList: Annotation<string[]>({
    reducer: (a, b) => b || a,
    default: () => [],
  }),
  interviewHistory: Annotation<{ question: string; answer: string }[]>({
    reducer: (a, b) => b || a,
    default: () => [],
  }),
  currentPhase: Annotation<string>({
    reducer: (a, b) => b || a,
    default: () => "Initializing System...",
  }),
  wizardCompleted: Annotation<boolean>({
    reducer: (a, b) => b || a,
    default: () => false,
  }),
});

import { StateGraph, START, END } from "@langchain/langgraph";
import { StateAnnotation } from "../state";
import { ChatGoogleGenerativeAI } from "@langchain/google-genai";
import { RunnableConfig } from "@langchain/core/runnables";
import { searchGithubProjectsTool, querySkillsAndExperiencesTool } from "../tools/vectorSearch";
import { dispatchCustomEvent } from "@langchain/core/callbacks/dispatch";

const llm = new ChatGoogleGenerativeAI({
  model: "gemini-3-flash-preview",
  temperature: 0.7, // slightly lower for truthfulness, but creative enough to draft
  apiKey: process.env.GEMINI_API_KEY,
});

async function draftCV(state: typeof StateAnnotation.State, config?: RunnableConfig) {
  await dispatchCustomEvent("progress", { msg: "Drafting Extended CV context..." }, config);
  // Find latest Human message
  const lastMsg =
    state.messages.length > 0 ? state.messages[state.messages.length - 1].content : "";

  const llmWithTools = llm.bindTools([searchGithubProjectsTool, querySkillsAndExperiencesTool]);
  const msgs: any[] = [
    {
      role: "system",
      content:
        "You are drafting the Extensive Master CV based on user requests. Call tools to fetch vector data from their github repos or demographic data if needed. Do not hallucinate. Provide raw markdown of the CV. Only output markdown.",
    },
    {
      role: "user",
      content: `Current CV:\n${state.workingExtendedCv || state.baseCv}\n\nRecent User Input:\n${lastMsg}`,
    },
  ];
  let draftCompletion = await llmWithTools.invoke(msgs, config);

  // Manual tool loop
  if (draftCompletion.tool_calls && draftCompletion.tool_calls.length > 0) {
    msgs.push(draftCompletion);
    for (const call of draftCompletion.tool_calls) {
      if (call.name === "search_github_projects") {
        const res = await searchGithubProjectsTool.invoke(call);
        msgs.push({ role: "tool", tool_call_id: call.id, content: res, name: call.name });
      } else if (call.name === "query_skills_and_experiences") {
        const res = await querySkillsAndExperiencesTool.invoke(call);
        msgs.push({ role: "tool", tool_call_id: call.id, content: res, name: call.name });
      }
    }
    draftCompletion = await llmWithTools.invoke(msgs, config);
  }

  let draftContent = "";
  if (typeof draftCompletion.content === "string") {
    draftContent = draftCompletion.content;
  }

  return { workingExtendedCv: draftContent };
}

// Critique 1
async function critiqueTone(state: typeof StateAnnotation.State, config?: RunnableConfig) {
  await dispatchCustomEvent(
    "progress",
    { msg: "[Critique Tone] Evaluating braggadocio vs impact..." },
    config
  );
  const evalResult = await llm.invoke(
    [
      {
        role: "system",
        content:
          "Analyze the following CV. Does it sound 'show off' or obnoxious? Too weak? Provide a 1-sentence critique. If perfect, simply output EXACTLY 'PASS'.",
      },
      { role: "user", content: state.workingExtendedCv },
    ],
    config
  );
  return { critiqueFeedback: evalResult.content === "PASS" ? [] : [`Tone: ${evalResult.content}`] };
}

// Critique 2
async function critiqueTruth(state: typeof StateAnnotation.State, config?: RunnableConfig) {
  await dispatchCustomEvent(
    "progress",
    { msg: "[Critique Truth] Validating claims against vector embeddings..." },
    config
  );
  const truthLlm = llm.bindTools([searchGithubProjectsTool]);
  const msgs: any[] = [
    {
      role: "system",
      content:
        "Analyze the CV for suspicious or overly complex claims. Use tool 'search_github_projects' to verify if they actually built what they claim. If lying or unsupported, provide a strict critique. If supported, exactly output 'PASS'.",
    },
    { role: "user", content: state.workingExtendedCv },
  ];
  let evalResult = await truthLlm.invoke(msgs, config);

  if (evalResult.tool_calls && evalResult.tool_calls.length > 0) {
    msgs.push(evalResult);
    for (const call of evalResult.tool_calls) {
      if (call.name === "search_github_projects") {
        const res = await searchGithubProjectsTool.invoke(call);
        msgs.push({ role: "tool", tool_call_id: call.id, content: res, name: call.name });
      }
    }
    evalResult = await truthLlm.invoke(msgs, config);
  }

  // Evaluate if tool calls were made or what text it replied with
  const critiqueText =
    typeof evalResult.content === "string"
      ? evalResult.content
      : JSON.stringify(evalResult.content);
  return { critiqueFeedback: critiqueText.includes("PASS") ? [] : [`Truth: ${critiqueText}`] };
}

// Critique 3
async function critiqueSkills(state: typeof StateAnnotation.State, config?: RunnableConfig) {
  await dispatchCustomEvent(
    "progress",
    { msg: "[Critique Skills] Cross-referencing ontology..." },
    config
  );
  const skillLlm = llm.bindTools([querySkillsAndExperiencesTool]);
  const msgs: any[] = [
    {
      role: "system",
      content:
        "Verify the CV strictly utilizes the skills found in the user's demographic DB. Query it. If it invents unlisted skills, fail it. Otherwise output 'PASS'.",
    },
    { role: "user", content: state.workingExtendedCv },
  ];
  let evalResult = await skillLlm.invoke(msgs, config);

  if (evalResult.tool_calls && evalResult.tool_calls.length > 0) {
    msgs.push(evalResult);
    for (const call of evalResult.tool_calls) {
      if (call.name === "query_skills_and_experiences") {
        const res = await querySkillsAndExperiencesTool.invoke(call);
        msgs.push({ role: "tool", tool_call_id: call.id, content: res, name: call.name });
      }
    }
    evalResult = await skillLlm.invoke(msgs, config);
  }
  const critiqueText =
    typeof evalResult.content === "string"
      ? evalResult.content
      : JSON.stringify(evalResult.content);
  return { critiqueFeedback: critiqueText.includes("PASS") ? [] : [`Skills: ${critiqueText}`] };
}

// Critique 4
async function critiqueProjects(state: typeof StateAnnotation.State, config?: RunnableConfig) {
  await dispatchCustomEvent(
    "progress",
    { msg: "[Critique Projects] Checking repository mappings..." },
    config
  );
  const evalResult = await llm.invoke(
    [
      {
        role: "system",
        content:
          "Review CV. Does it accurately portray proper software engineering projects? Say 'PASS' if good, otherwise point out gaps.",
      },
      { role: "user", content: state.workingExtendedCv },
    ],
    config
  );
  return {
    critiqueFeedback: evalResult.content === "PASS" ? [] : [`Projects: ${evalResult.content}`],
  };
}

// Critique 5
async function critiqueExperiences(state: typeof StateAnnotation.State, config?: RunnableConfig) {
  await dispatchCustomEvent(
    "progress",
    { msg: "[Critique Experiences] Asserting timeline continuity..." },
    config
  );
  const evalResult = await llm.invoke(
    [
      {
        role: "system",
        content:
          "Review timeline consistency in the CV experiences. Say 'PASS' if there are no magical overlapping full-time conflicts or impossibilities. Else explain.",
      },
      { role: "user", content: state.workingExtendedCv },
    ],
    config
  );
  return {
    critiqueFeedback: evalResult.content === "PASS" ? [] : [`Experiences: ${evalResult.content}`],
  };
}

async function consolidateCV(state: typeof StateAnnotation.State, config?: RunnableConfig) {
  await dispatchCustomEvent("progress", { msg: "Consolidating 5-Phase critiques..." }, config);
  if (state.critiqueFeedback.length > 0) {
    // Redraft
    await dispatchCustomEvent(
      "progress",
      { msg: `Found ${state.critiqueFeedback.length} critique issues. Repairing...` },
      config
    );
    const fixed = await llm.invoke(
      [
        {
          role: "system",
          content: `You must fix the CV given the following strict critiques:\n${state.critiqueFeedback.join("\n")}\n\nOutput only fixed markdown CV.`,
        },
        { role: "user", content: state.workingExtendedCv },
      ],
      config
    );

    const fixedContent =
      typeof fixed.content === "string" ? fixed.content : state.workingExtendedCv;

    // Return fixed CV and clear critiques
    return {
      workingExtendedCv: fixedContent,
      critiqueFeedback: [],
      messages: [
        { role: "assistant", content: "I have updated the CV based on multiple critique phases." },
      ],
    };
  }

  return {
    messages: [
      {
        role: "assistant",
        content:
          "I have finalized the CV iteration and it passes all 5 critique validation stages.",
      },
    ],
  };
}

const workflow = new StateGraph(StateAnnotation)
  .addNode("Draft_CV", draftCV)
  .addNode("Critique_Tone", critiqueTone)
  .addNode("Critique_Truth", critiqueTruth)
  .addNode("Critique_Skills", critiqueSkills)
  .addNode("Critique_Projects", critiqueProjects)
  .addNode("Critique_Experiences", critiqueExperiences)
  .addNode("Consolidate_Feedback", consolidateCV)

  // Fork
  .addEdge(START, "Draft_CV")
  .addEdge("Draft_CV", "Critique_Tone")
  .addEdge("Draft_CV", "Critique_Truth")
  .addEdge("Draft_CV", "Critique_Skills")
  .addEdge("Draft_CV", "Critique_Projects")
  .addEdge("Draft_CV", "Critique_Experiences")

  // Join
  .addEdge("Critique_Tone", "Consolidate_Feedback")
  .addEdge("Critique_Truth", "Consolidate_Feedback")
  .addEdge("Critique_Skills", "Consolidate_Feedback")
  .addEdge("Critique_Projects", "Consolidate_Feedback")
  .addEdge("Critique_Experiences", "Consolidate_Feedback")

  .addEdge("Consolidate_Feedback", END);

export const improverSubGraph = workflow.compile();

import { StateAnnotation, DbDirective } from "../state";
import { pool } from "../../db/client";
import { exec } from "child_process";
import * as fs from "fs/promises";
import * as path from "path";
import { promisify } from "util";
import { dispatchCustomEvent } from "@langchain/core/callbacks/dispatch";
