const execAsync = promisify(exec);
env.allowLocalModels = true;

export class EmbedderPipeline {
  static task = "feature-extraction";
  static model = "Xenova/all-MiniLM-L6-v2";
  static instancePromise: Promise<any> | null = null;
  static instance: any = null;

  static async getInstance() {
    if (!this.instancePromise) {
      this.instancePromise = pipeline(this.task as any, this.model, { quantized: true });
      this.instance = await this.instancePromise;
    }
    return this.instance;
  }
}

// ---------------- Tools ------------------ //

const fetchGithubTool = tool(
  async ({ handle }, config) => {
    await dispatchCustomEvent("progress", { msg: `Fetching GitHub repos for ${handle}` }, config);
    const fetchHeaders: any = {};
    if (process.env.GITHUB_TOKEN)
      fetchHeaders["Authorization"] = `Bearer ${process.env.GITHUB_TOKEN}`;
    let repos: any[] = [];
    let page = 1;
    while (true) {
      const response = await fetch(
        `https://api.github.com/users/${handle}/repos?type=owner&sort=updated&per_page=100&page=${page}`,
        { headers: fetchHeaders }
      );
      const batch = await response.json();
      if (!Array.isArray(batch) || batch.length === 0) break;
      repos = repos.concat(batch);
      page++;
    }
    const finalRepos = repos
      .filter((r: any) => !r.fork)
      .map((r: any) => ({
        name: r.name,
        url: r.html_url,
        description: r.description,
      }));
    await dispatchCustomEvent(
      "progress",
      { msg: `Found ${finalRepos.length} target repositories.` },
      config
    );
    return JSON.stringify(finalRepos);
  },
  {
    name: "fetch_github_repos",
    description: "Fetch public non-fork repos for a given github handle",
    schema: z.object({ handle: z.string() }),
  }
);

const cloneRepoTool = tool(
  async ({ repoUrl, repoName, index, total }, config) => {
    const tmpDir = path.resolve(process.cwd(), "../../temp_repos");
    const repoPath = path.join(tmpDir, repoName);
    let exists = false;
    try {
      await fs.access(repoPath);
      exists = true;
    } catch {}

    const tag = index !== undefined && total !== undefined ? `[Repo ${index}/${total}] ` : "";

    if (!exists) {
      await dispatchCustomEvent("progress", { msg: `${tag}Cloning ${repoName}...` }, config);
      await execAsync(`git clone --depth 1 ${repoUrl} ${repoPath}`);
    } else {
      await dispatchCustomEvent(
        "progress",
        { msg: `${tag}Pulling latest for ${repoName}...` },
        config
      );
      try {
        await execAsync(`git -C ${repoPath} pull`);
      } catch {}
    }
    return `Repository ${repoName} is securely sandbox mounted at ${repoPath}`;
  },
  {
    name: "clone_repo",
    description:
      "Clones a git repo to the local filesystem for the underlying deepagent backend to access",
    schema: z.object({
      repoName: z.string(),
      repoUrl: z.string(),
      index: z.number().optional(),
      total: z.number().optional(),
    }),
  }
);

const embedProjectTool = tool(
  async ({ repoName, textContent, userProfileId, index, total }, config) => {
    const tag = index !== undefined && total !== undefined ? `[Repo ${index}/${total}] ` : "";
    await dispatchCustomEvent(
      "progress",
      { msg: `${tag}Embedding ${repoName} high-level logic...` },
      config
    );
    const splitter = new RecursiveCharacterTextSplitter({ chunkSize: 4000, chunkOverlap: 200 });
    const docs = await splitter.createDocuments([textContent.slice(0, 16000)]);
    const embedder = await EmbedderPipeline.getInstance();

    const BATCH_SIZE = 16;
    const dbWrites: DbDirective[] = [];
    dbWrites.push({
      targetTable: "projects_raw_text",
      action: "upsert",
      data: { repo_name: repoName, raw_text: textContent, user_profile_id: userProfileId },
    });

    for (let i = 0; i < docs.length; i += BATCH_SIZE) {
      const batchDocs = docs.slice(i, i + BATCH_SIZE);
      const batchTexts = batchDocs.map((d) => d.pageContent);
      try {
        const response = await embedder(batchTexts, { pooling: "mean", normalize: true });
        const embeddingsList = response.tolist();
        for (let j = 0; j < embeddingsList.length; j++) {
          dbWrites.push({
            targetTable: "project_embeddings",
            action: "insert",
            data: {
              chunk_index: i + j,
              chunk_text: batchTexts[j],
              embedding: `[${embeddingsList[j].join(",")}]`,
              _repoNameRef: repoName,
            },
          });
        }
      } catch {}
    }
    return JSON.stringify(dbWrites);
  },
  {
    name: "embed_project",
    description: "Generate vector embeddings for repository text and return DB directives",
    schema: z.object({
      repoName: z.string(),
      textContent: z.string(),
      userProfileId: z.number().optional(),
      index: z.number().optional(),
      total: z.number().optional(),
    }),
  }
);

// ---------------- DeepAgent Setup ------------------ //

const fsBackend = new FilesystemBackend({
  rootDir: path.resolve(process.cwd(), "../../temp_repos"),
});

const deeperIngestionAgent = createDeepAgent({
  name: "ingestion",
  model: new ChatGoogleGenerativeAI({
    model: "gemini-3-flash-preview",
    temperature: 1,
    apiKey: process.env.GEMINI_API_KEY,
  }),
  backend: fsBackend,
  systemPrompt: `You are an elite Repository Processing deepagent. 
1. Use fetch_github_repos to get the list of repositories available for this handle.
2. For EACH repository found (pass \`index\` and \`total\` parameters when cloning and embedding):
   a. Use clone_repo to clone it.
   b. CRITICAL: Use your sandboxed filesystem tools to explicitly read "package.json", "Cargo.toml", "requirements.txt", or any index file present. You MUST understand its dependencies and high-level architectural logic.
   c. Summarize this logic deeply, including specific frameworks discovered.
   d. Run embed_project on the analyzed repo to save your architectural context.
3. When finished with ALL repos, wrap up your findings and append the Database directives to your final message output in JSON format surrounded by <directives> tags.`,
  tools: [fetchGithubTool, cloneRepoTool, embedProjectTool],
});

// ---------------- StateGraph Node ------------------ //

export async function ingestionSubGraph(
  state: typeof StateAnnotation.State,
  config?: RunnableConfig
) {
  // 1. We execute the deepagent once using the current handle.
  const runResult = await deeperIngestionAgent.invoke(
    {
      messages: [
        {
          role: "user",
          content: `Please ingest github handle: ${state.githubHandle} and output DB directives.`,
        },
      ],
    } as any,
    config
  );

  const lastMsg = runResult.messages[runResult.messages.length - 1].content.toString();

  // 2. Parse out directives from the deepagent's final output
  const directivesMatch = lastMsg.match(/<directives>([\s\S]*?)<\/directives>/);
  let parsedDirectives: DbDirective[] = [];
  if (directivesMatch && directivesMatch[1]) {
    try {
      parsedDirectives = JSON.parse(directivesMatch[1]);
    } catch {}
  }

  return { pendingDbWrites: parsedDirectives, currentPhase: "Build Ontology" };
}

import { ProfileGraphState, StateAnnotation, DbDirective } from "../state";
import { StateGraph, START, END } from "@langchain/langgraph";
import { ChatGoogleGenerativeAI } from "@langchain/google-genai";
import { INTERVIEWER_PROMPTS } from "../prompts/interviewer";
import { dispatchCustomEvent } from "@langchain/core/callbacks/dispatch";
import { RunnableConfig } from "@langchain/core/runnables";
import {
  OnboardingProfileSchema,
  MissingInfoSchema,
  EnhancedInterviewSchema,
} from "../prompts/structuralSchemas";
import { pool } from "../../db/client";

const llm = new ChatGoogleGenerativeAI({
  model: "gemini-3-flash-preview",
  temperature: 1,
  apiKey: process.env.GEMINI_API_KEY,
});

async function evaluateCompleteness(state: typeof StateAnnotation.State, config?: RunnableConfig) {
  await dispatchCustomEvent(
    "progress",
    { msg: "Evaluating profile completeness via structured outputs..." },
    config
  );

  // Fetch latest context from raw DB reads (if not passed in state, though state should have it)
  let extendedCv = state.baseCv || "";
  if (state.userProfileId) {
    const r = await pool.query("SELECT master_extended_cv FROM user_profiles WHERE id = $1", [
      state.userProfileId,
    ]);
    if (r.rows[0]?.master_extended_cv) extendedCv = r.rows[0].master_extended_cv;
  }

  const evaluatorWithStructure = llm.withStructuredOutput(OnboardingProfileSchema);

  const evaluation = await evaluatorWithStructure.invoke(
    [
      { role: "system", content: INTERVIEWER_PROMPTS.completenessSystem },
      { role: "user", content: `Here is the current CV and profile info: \n\n${extendedCv}` },
    ],
    config
  );

  return {
    missingInfoList: evaluation.missing_structural_areas || [],
    missingCount: evaluation.missing_structural_areas
      ? evaluation.missing_structural_areas.length
      : 0,
  };
}

async function directInterview(state: typeof StateAnnotation.State, config?: RunnableConfig) {
  if (state.missingCount === 0) {
    await dispatchCustomEvent(
      "progress",
      { msg: "Profile complete. Bypassing interview." },
      config
    );
    return { interviewHistory: state.interviewHistory }; // no update
  }

  await dispatchCustomEvent(
    "progress",
    { msg: `Drafting next interview question. Missing ${state.missingCount} areas.` },
    config
  );

  const targetArea = state.missingInfoList[0];
  const interviewLlm = llm.withStructuredOutput(EnhancedInterviewSchema);

  // History
  const historyText =
    state.interviewHistory?.map((h) => `Q: ${h.question}\nA: ${h.answer}`).join("\n") ||
    "No previous questions.";

  const nextQ = await interviewLlm.invoke(
    [
      { role: "system", content: INTERVIEWER_PROMPTS.interviewerSystem },
      { role: "user", content: `Missing area: ${targetArea}. History:\n${historyText}` },
    ],
    config
  );

  const updatedHistory = [
    ...(state.interviewHistory || []),
    {
      question: nextQ.next_question_to_ask,
      answer: "", // to be filled by user
    },
  ];

  return {
    interviewHistory: updatedHistory,
  };
}

async function improveCV(state: typeof StateAnnotation.State, config?: RunnableConfig) {
  // Only improve if there are answers to process or we forcibly requested an update
  if (!state.interviewHistory || state.interviewHistory.length === 0) {
    return { pendingDbWrites: [] };
  }

  // Check last answer
  const lastInteraction = state.interviewHistory[state.interviewHistory.length - 1];
  if (!lastInteraction.answer || lastInteraction.answer.trim() === "") {
    // User hasn't answered yet, don't improve
    return { pendingDbWrites: [] };
  }

  await dispatchCustomEvent("progress", { msg: "Refining Master CV with new answers..." }, config);

  let extendedCv = state.baseCv || "";
  if (state.userProfileId) {
    const r = await pool.query("SELECT master_extended_cv FROM user_profiles WHERE id = $1", [
      state.userProfileId,
    ]);
    if (r.rows[0]?.master_extended_cv) extendedCv = r.rows[0].master_extended_cv;
  }

  const res = await llm.invoke(
    [
      { role: "system", content: INTERVIEWER_PROMPTS.cvImproverSystem },
      {
        role: "user",
        content: `Context: ${extendedCv}\n\nQ: ${lastInteraction.question}\nA: ${lastInteraction.answer}\n\nPlease output the completely updated markdown CV.`,
      },
    ],
    config
  );

  const newCv = typeof res.content === "string" ? res.content : JSON.stringify(res.content);

  const writes: DbDirective[] = [];
  if (state.userProfileId) {
    writes.push({
      targetTable: "user_profiles",
      action: "update",
      data: { master_extended_cv: newCv },
    });
  }

  return { pendingDbWrites: writes };
}

// Subgraph orchestration for Interviewer
const workflow = new StateGraph(StateAnnotation)
  .addNode("Evaluate_Completeness", evaluateCompleteness)
  .addNode("Improve_CV", improveCV)
  .addNode("Direct_Interview", directInterview)
  // Flow: Evaluate -> Improve (if pending answers) -> generate new question
  .addEdge(START, "Evaluate_Completeness")
  .addEdge("Evaluate_Completeness", "Improve_CV")
  .addEdge("Improve_CV", "Direct_Interview")
  .addEdge("Direct_Interview", END);

export const interviewerSubGraph = workflow.compile();

import { tool } from "@langchain/core/tools";
import { z } from "zod";
import { pool } from "../../db/client";
import { EmbedderPipeline } from "../subgraphs/ingestion"; // re-use the same embedder singleton

export const searchGithubProjectsTool = tool(
  async ({ query, limit = 5 }) => {
    try {
      const embedder = await EmbedderPipeline.getInstance();
      const embeddingResult = await embedder(query, { pooling: "mean", normalize: true });

      // Convert Float32Array to pgvector string format: '[val1, val2, ...]'
      const embeddingArray = Array.from(embeddingResult.data);
      const vectorString = "[" + embeddingArray.join(",") + "]";

      // Query pgvector for the closest chunks using cosine distance (<=>)
      // Join with projects_raw_text to get the repo_name
      const result = await pool.query(
        `
            SELECT 
                r.repo_name,
                e.chunk_text,
                (e.embedding <=> $1) as distance
            FROM project_embeddings e
            JOIN projects_raw_text r ON e.project_id = r.id
            ORDER BY distance ASC
            LIMIT $2
            `,
        [vectorString, limit]
      );

      if (result.rows.length === 0) {
        return "No relevant project context found for this query.";
      }

      return result.rows
        .map(
          (row) =>
            `\n--- Match from Repo: ${row.repo_name} (Distance: ${row.distance.toFixed(3)}) ---\n${row.chunk_text}\n`
        )
        .join("\n");
    } catch (e: any) {
      return `Error searching vector embeddings: ${e.message}`;
    }
  },
  {
    name: "search_github_projects",
    description:
      "Search across all user GitHub repositories using semantic vector search. Use this to find specific code implementations, project purposes, and verify technical claims.",
    schema: z.object({
      query: z
        .string()
        .describe(
          "The semantic query or claim to search for (e.g. 'Used React with Redux for state management')"
        ),
      limit: z.number().optional().describe("Number of context chunks to return (default is 5)"),
    }),
  }
);

