function routeCritique(state: AgentStateType) {
  if ((state.iterations || 0) >= 3) {
    return END;
  }
  if (state.next_action === "ACCEPT") {
    return END;
  } else if (state.next_action === "RESELECT_PROJECTS") {
    return "Profile_Match";
  } else {
    return "Draft_Docs";
  }
}

