import { useState, useCallback, useEffect } from "react";

export type SSEMessage = {
  type: string;
  message?: string;
  data?: any;
};

export function useBackendAgent(endpoint: string) {
  const [isRunning, setIsRunning] = useState(false);
  const [logs, setLogs] = useState<string[]>([]);
  const [progress, setProgress] = useState(0);
  const [activeNodes, setActiveNodes] = useState<string[]>([]);
  const [currentPhase, setCurrentPhase] = useState<string>("Parsing Github...");
  const [currentQuestion, setCurrentQuestion] = useState<string | null>(null);
  const [isWizardComplete, setIsWizardComplete] = useState<boolean>(false);

  useEffect(() => {
    if (!isRunning) return;

    const eventSource = new EventSource(endpoint);

    eventSource.onmessage = (event) => {
      const parsed = JSON.parse(event.data) as SSEMessage;

      if (parsed.type === "ping") return;

      if (parsed.type === "log") {
        setLogs((prev) => [...prev, parsed.message!]);
      }

      if (parsed.type === "node_start") {
        setActiveNodes((prev) => [...prev, parsed.data.node]);
        setProgress(parsed.data.progress || 0);
      }

      if (parsed.type === "node_end") {
        setActiveNodes((prev) => prev.filter((n) => n !== parsed.data.node));
      }

      if (parsed.type === "interrupt") {
        setCurrentPhase(parsed.data.phase || "Interview Phase");
        setCurrentQuestion(parsed.data.question);
        setLogs((prev) => [...prev, "Agent paused for user input..."]);
      }

      if (parsed.type === "complete") {
        setIsRunning(false);
        setIsWizardComplete(true);
        setCurrentPhase("Onboarding Complete");
        eventSource.close();
      }
    };

    eventSource.onerror = (err) => {
      console.error("SSE Error:", err);
      eventSource.close();
      setIsRunning(false);
    };

    return () => {
      eventSource.close();
    };
  }, [isRunning, endpoint]);

  const startAgent = useCallback(async (payload: any) => {
    setIsRunning(true);
    setLogs([]);
    setCurrentQuestion(null);
    setProgress(0);

    // Post to trigger execution backend, which then broadcasts to SSE
    await fetch("/api/ingest/start", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
  }, []);

  const submitAnswer = useCallback(async (answer: string) => {
    setCurrentQuestion(null);
    await fetch("/api/ingest/answer", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ answer }),
    });
  }, []);

  return {
    isRunning,
    logs,
    progress,
    activeNodes,
    currentPhase,
    currentQuestion,
    isWizardComplete,
    startAgent,
    submitAnswer,
  };
}

import { useState } from "react";
import { cvImproverGraph } from "../agent/cvImproverGraph";

export function useImproverAgent() {
  const [isRunning, setIsRunning] = useState(false);
  const [progress, setProgress] = useState<{ node: string; message: string }[]>([]);
  const [activeNodes, setActiveNodes] = useState<string[]>([]);
  const [streamingTokens, setStreamingTokens] = useState<Record<string, string>>({});

  const [score, setScore] = useState<number>(0);
  const [critique, setCritique] = useState<string>("");
  const [needsHumanInput, setNeedsHumanInput] = useState(false);
  const [questions, setQuestions] = useState<string[]>([]);
  const [threadId, setThreadId] = useState<string>("");
  const [currentCv, setCurrentCv] = useState<string>("");
  const [error, setError] = useState<string | null>(null);

  const addProgress = (msg: string) => setProgress((p) => [...p, { node: "System", message: msg }]);

  const runImprover = async (baseCv: string, githubUsername: string) => {
    if (!baseCv || !githubUsername) {
      setError("Please provide a base CV and GitHub username.");
      return;
    }

    setIsRunning(true);
    setError(null);
    setNeedsHumanInput(false);
    setProgress([]);
    setStreamingTokens({});
    setActiveNodes([]);

    const newThreadId = Math.random().toString(36).substring(7);
    setThreadId(newThreadId);

    try {
      addProgress("Fetching GitHub portfolio...");
      const res = await fetch(
        `https://api.github.com/users/${githubUsername}/repos?per_page=100&sort=updated`
      );
      if (!res.ok) throw new Error("Failed to fetch GitHub repositories. Check the username.");
      const repos = await res.json();
      addProgress(`Found ${repos.length} repositories.`);

      const initialState = {
        current_cv: baseCv,
        github_portfolio: repos,
        iterations: 0,
        user_answers: {},
      };

      addProgress("Starting 10/10 Improvement Loop...");

      await executeGraph(initialState, newThreadId);
    } catch (err: any) {
      setError(err.message || "An error occurred.");
      addProgress("Workflow failed.");
      setIsRunning(false);
    }
  };

  const submitAnswers = async (answers: Record<string, string>) => {
    setIsRunning(true);
    setNeedsHumanInput(false);
    setError(null);
    setStreamingTokens((prev) => {
      // Clear streaming tokens for nodes that will re-run
      const next = { ...prev };
      delete next["Rewrite_CV"];
      delete next["Evaluate_CV"];
      return next;
    });

    try {
      addProgress("Resuming workflow with human input...");
      const config = { configurable: { thread_id: threadId } };
      await cvImproverGraph.updateState(config, { user_answers: answers });
      await executeGraph(null, threadId);
    } catch (err: any) {
      setError(err.message || "An error occurred.");
      addProgress("Workflow failed.");
      setIsRunning(false);
    }
  };

  const executeGraph = async (initialState: any, tid: string) => {
    const config = {
      configurable: {
        thread_id: tid,
        onChunk: (nodeName: string, text: string) => {
          setStreamingTokens((prev) => ({
            ...prev,
            [nodeName]: (prev[nodeName] || "") + text,
          }));
        },
      },
    };

    const stream = await cvImproverGraph.stream(initialState, config);

    for await (const event of stream) {
      const nodeNames = Object.keys(event);
      setActiveNodes(nodeNames);

      for (const nodeName of nodeNames) {
        const state = await cvImproverGraph.getState(config);

        if (nodeName === "Match_GitHub_Projects")
          addProgress(`Matched GitHub Projects: ${state.values.selected_projects?.join(", ")}`);
        else if (nodeName === "Fetch_Repo_Context")
          addProgress("Fetched deep context from selected repositories.");
        else if (nodeName === "Evaluate_CV")
          addProgress(`Evaluated CV. Score: ${state.values.score}/10`);
        else if (nodeName === "Rewrite_CV")
          addProgress("Rewrote CV based on critique and GitHub context.");

        if (state.values.score) setScore(state.values.score);
        if (state.values.critique) setCritique(state.values.critique);
        if (state.values.current_cv) setCurrentCv(state.values.current_cv);
      }
    }

    const finalState = await cvImproverGraph.getState(config);
    if (finalState.next.includes("Ask_User")) {
      setQuestions(finalState.values.questions_for_user || []);
      setNeedsHumanInput(true);
      setActiveNodes(["Ask_User"]);
      addProgress("Paused: Waiting for human input to clarify STAR details.");
    } else {
      setActiveNodes(["END"]);
      addProgress("Workflow Complete! Achieved SOTA standard.");
    }
    setIsRunning(false);
  };

  return {
    runImprover,
    submitAnswers,
    isRunning,
    progress,
    activeNodes,
    streamingTokens,
    score,
    critique,
    needsHumanInput,
    questions,
    currentCv,
    error,
    setError,
  };
}

import { useState } from "react";
import { appGraph } from "../agent/graph";

export function useTailorAgent() {
  const [isRunning, setIsRunning] = useState(false);
  const [progress, setProgress] = useState<{ node: string; message: string }[]>([]);
  const [activeNodes, setActiveNodes] = useState<string[]>([]);
  const [streamingTokens, setStreamingTokens] = useState<Record<string, string>>({});
  const [result, setResult] = useState<{
    cv: string;
    coverLetter: string;
    answers?: string;
  } | null>(null);
  const [error, setError] = useState<string | null>(null);

  const runTailor = async (
    jobDescription: string,
    baseCv: string,
    githubUsername: string,
    companyQuestions: string = ""
  ) => {
    if (!jobDescription || !baseCv || !githubUsername) {
      setError("Please fill in all required fields.");
      return;
    }

    setIsRunning(true);
    setError(null);
    setProgress([]);
    setResult(null);
    setActiveNodes([]);
    setStreamingTokens({});

    const addProgress = (msg: string) =>
      setProgress((p) => [...p, { node: "System", message: msg }]);

    try {
      addProgress("Fetching GitHub portfolio...");
      const res = await fetch(
        `https://api.github.com/users/${githubUsername}/repos?per_page=100&sort=updated`
      );
      if (!res.ok) throw new Error("Failed to fetch GitHub repositories. Check the username.");
      const repos = await res.json();
      addProgress(`Found ${repos.length} repositories.`);

      const initialState = {
        job_description: jobDescription,
        base_cv: baseCv,
        github_portfolio: repos,
        jd_analysis: {},
        selected_projects: [],
        repo_deep_dives: {},
        draft_cv: "",
        draft_cover_letter: "",
        company_questions: companyQuestions,
        draft_answers: "",
        critique_truth: "",
        critique_star: "",
        critique_verbosity: "",
        critique_tone: "",
        critique_feedback: "",
        next_action: "",
        iterations: 0,
      };

      addProgress("Starting Agentic Workflow...");

      const newThreadId = Math.random().toString(36).substring(7);
      const config = {
        configurable: {
          thread_id: newThreadId,
          onChunk: (nodeName: string, text: string) => {
            setStreamingTokens((prev) => ({
              ...prev,
              [nodeName]: (prev[nodeName] || "") + text,
            }));
          },
        },
      };

      const stream = await appGraph.streamEvents(initialState, {
        ...config,
        version: "v2",
        recursionLimit: 150,
      });

      // We will also use the standard .stream() loop for node completion events
      // Wait, .streamEvents captures EVERYTHING. Let's use standard .stream() but passing config!
      // In graph runner it is actually appGraph.stream(initialState, config)

      const graphStream = await appGraph.stream(initialState, { ...config, recursionLimit: 150 });

      for await (const event of graphStream) {
        // Event is an object with node name as key
        const nodeNames = Object.keys(event);
        setActiveNodes(nodeNames);

        for (const nodeName of nodeNames) {
          const stepState = (event as Record<string, any>)[nodeName];

          if (nodeName === "Analyze_JD")
            addProgress("Analyzed Job Description. Extracted core skills.");
          else if (nodeName === "Profile_Match")
            addProgress(
              `Matched Profile. Selected projects: ${stepState.selected_projects?.join(", ")}`
            );
          else if (nodeName === "Fetch_Repo_Context")
            addProgress("Fetched deep context from selected repositories.");
          else if (nodeName === "Draft_Docs")
            addProgress(`Drafted CV and Cover Letter (Iteration ${stepState.iterations}).`);
          else if (nodeName.startsWith("Critique_")) {
            addProgress(`${nodeName} completed evaluation.`);
          }
        }
      }

      const finalGraphState = await appGraph.getState(config);
      if (finalGraphState && finalGraphState.values.draft_cv) {
        setResult({
          cv: finalGraphState.values.draft_cv,
          coverLetter: finalGraphState.values.draft_cover_letter,
          answers: finalGraphState.values.draft_answers,
        });
        addProgress("Workflow Complete!");
        setActiveNodes(["END"]);
      }
    } catch (err: any) {
      setError(err.message || "An error occurred during execution.");
      addProgress("Workflow failed.");
    } finally {
      setIsRunning(false);
    }
  };

  return {
    runTailor,
    isRunning,
    progress,
    activeNodes,
    streamingTokens,
    result,
    error,
    setError,
  };
}

